// Roboto (Apache 2.0) subset to Latin + FULL Vietnamese (Regular + Bold),
// base64 TTF. Replaces the earlier Noto subset missing composed Vietnamese glyphs.
// Kept as base64 in a .ts module so it survives the tsc→dist build. Used by
// cv/export/pdf.ts (pdfkit registerFont).
export const NOTO_SANS_VI_B64 = "";
export const notoSansViBuffer = (): Buffer => Buffer.from(NOTO_SANS_VI_B64, "base64");

export const NOTO_SANS_VI_BOLD_B64 = "";
export const notoSansViBoldBuffer = (): Buffer => Buffer.from(NOTO_SANS_VI_BOLD_B64, "base64");
